"use strict";parserFactory.register("novelupdates.com",()=>new NovelUpdatesParser);class NovelUpdatesParser extends Parser{constructor(){super()}getChapterUrls(e){return NovelUpdatesParser.fetchChapterUrls(e).then(function(e){let t=e.map(e=>util.hyperLinkToChapter(e));return Promise.resolve(t.reverse())})}static fetchChapterUrls(e){let t=NovelUpdatesParser.findPagesWithToC(e);return Promise.all(t.map(e=>NovelUpdatesParser.fetchChapterListFromPage(e))).then(function(t){return t.reduce(function(e,t){return e.concat(t)},NovelUpdatesParser.chapterLinksFromDom(e))})}static fetchChapterListFromPage(e){return HttpClient.wrapFetch(e).then(function(e){return Promise.resolve(NovelUpdatesParser.chapterLinksFromDom(e.responseXML))})}static chapterLinksFromDom(e){return[...e.querySelectorAll("table#myTable tbody tr")].map(NovelUpdatesParser.chapterLinksFromRow).filter(e=>null!==e)}static chapterLinksFromRow(e){let t=[...e.querySelectorAll("a")];return 0<t.length?t[t.length-1]:null}static findPagesWithToC(e){let t=[],r=e.querySelector("div.digg_pagination");if(null!==r){let a=NovelUpdatesParser.getPageValueOfLastTocPage(r);for(let r=2;r<=a;++r)t.push(e.baseURI+"?pg="+r)}return t}static getPageValueOfLastTocPage(e){return[...e.querySelectorAll("a")].reduce(function(e,t){let r=NovelUpdatesParser.getPageSearchParameter(t);return r>e?r:e},-1)}static getPageSearchParameter(e){let t=e.search;if(t.startsWith("?pg="))return parseInt(t.substring(4))}findContent(e){return e.body}extractTitleImpl(e){return e.querySelector("div.seriestitlenu")}extractAuthor(e){let t=e.querySelector("div#showauthors a");return null!==t?t.textContent:super.extractAuthor(e)}}